func New(config ...Config) fiber.Handler {

	cfg := configDefault(config...)

	return func(c fiber.Ctx) error {

		if cfg.Next != nil && cfg.Next(c) {
			return c.Next()
		}

		if !c.IsProxyTrusted() {
			return cfg.Error
		}

		if !cfg.IsEarlyData(c) {
			return c.Next()
		}

		if cfg.AllowEarlyData(c) {
			_ = c.Locals(localsKeyAllowed, true)
			return c.Next()
		}

		return cfg.Error
	}
}
